--
-- Table structure for table `items`
--

DROP TABLE IF EXISTS `items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `items` (
  `id` int NOT NULL AUTO_INCREMENT,
  `sku` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `stock` int DEFAULT '0',
  `min_stock` int DEFAULT '0',
  `plan_file` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `active` tinyint(1) DEFAULT '1',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `reorder_status` varchar(12) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reorder_proveidor` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reorder_notes` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reorder_updated_at` datetime DEFAULT NULL,
  `reorder_qty_comprada` int NOT NULL DEFAULT '0',
  `reorder_qty_entregada` int NOT NULL DEFAULT '0',
  `reorder_qty_entrada` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `sku` (`sku`)
) ENGINE=InnoDB AUTO_INCREMENT=2053 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

